import { Progress as ProgressPrimitive } from '@base-ui/react/progress';
import { forwardRef, type ComponentRef } from 'react';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Progress.module.css';

const Progress = forwardRef<
  ComponentRef<typeof ProgressPrimitive.Root>,
  ProgressPrimitive.Root.Props
>(function Progress({ children, ...props }, ref) {
  return (
    <ProgressRoot ref={ref} {...props}>
      {children}
      <ProgressTrack>
        <ProgressIndicator />
      </ProgressTrack>
    </ProgressRoot>
  );
});

const ProgressRoot = forwardRef<
  ComponentRef<typeof ProgressPrimitive.Root>,
  ProgressPrimitive.Root.Props
>(function ProgressRoot({ className, ...props }, ref) {
  return (
    <ProgressPrimitive.Root
      ref={ref}
      data-slot="progress-root"
      className={mergeClassName(className, styles.root)}
      {...props}
    />
  );
});

const ProgressTrack = forwardRef<
  ComponentRef<typeof ProgressPrimitive.Track>,
  ProgressPrimitive.Track.Props
>(function ProgressTrack({ className, ...props }, ref) {
  return (
    <ProgressPrimitive.Track
      ref={ref}
      data-slot="progress-track"
      className={mergeClassName(className, styles.track)}
      {...props}
    />
  );
});

const ProgressIndicator = forwardRef<
  ComponentRef<typeof ProgressPrimitive.Indicator>,
  ProgressPrimitive.Indicator.Props
>(function ProgressIndicator({ className, ...props }, ref) {
  return (
    <ProgressPrimitive.Indicator
      ref={ref}
      data-slot="progress-indicator"
      className={mergeClassName(className, styles.indicator)}
      {...props}
    />
  );
});

const ProgressLabel = forwardRef<
  ComponentRef<typeof ProgressPrimitive.Label>,
  ProgressPrimitive.Label.Props
>(function ProgressLabel({ className, ...props }, ref) {
  return (
    <ProgressPrimitive.Label
      ref={ref}
      data-slot="progress-label"
      className={mergeClassName(className, styles.label)}
      {...props}
    />
  );
});

const ProgressValue = forwardRef<
  ComponentRef<typeof ProgressPrimitive.Value>,
  ProgressPrimitive.Value.Props
>(function ProgressValue({ className, ...props }, ref) {
  return (
    <ProgressPrimitive.Value
      ref={ref}
      data-slot="progress-value"
      className={mergeClassName(className, styles.value)}
      {...props}
    />
  );
});

export { Progress, ProgressRoot, ProgressTrack, ProgressIndicator, ProgressLabel, ProgressValue };

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: grid;
    grid-template-columns: minmax(0, 1fr) auto;
    gap: var(--progress-gap, 0.5rem);
    width: var(--progress-width, 12rem);
    color: var(--progress-color, var(--color-foreground));
  }

  .label {
    font-size: var(--progress-label-font-size, var(--text-sm));
    font-weight: var(--progress-label-font-weight, var(--weight-regular));
    line-height: var(--progress-label-line-height, var(--line-height-text-sm));
    color: var(--progress-label-color, currentColor);
  }

  .value {
    font-size: var(--progress-value-font-size, var(--text-sm));
    font-weight: var(--progress-value-font-weight, var(--weight-regular));
    line-height: var(--progress-value-line-height, var(--line-height-text-sm));
    justify-self: end;
    color: var(--progress-value-color, currentColor);
    text-align: right;
  }

  .track {
    grid-column: 1 / -1;
    display: block;
    overflow: hidden;
    width: 100%;
    height: var(--progress-track-height, 0.5rem);
    border-radius: var(--progress-track-radius, var(--radius-full));
    background-color: var(--progress-track-bg, var(--color-muted));
    box-shadow: inset 0 0 0 var(--progress-track-border-width, var(--border-width-sm))
      var(--progress-track-border-color, var(--color-border));
  }

  .indicator {
    display: block;
    height: 100%;
    border-radius: var(--progress-indicator-radius, inherit);
    background-color: var(--progress-indicator-bg, var(--color-primary));
    transition: width var(--progress-indicator-transition, var(--transition-default));

    &[data-indeterminate] {
      width: var(--progress-indicator-indeterminate-width, 35%);
      animation: var(
        --progress-indicator-indeterminate-animation,
        progress-indeterminate 1.5s ease-in-out infinite
      );
    }

    @media (prefers-reduced-motion: reduce) {
      &[data-indeterminate] {
        animation: none;
        transform: translateX(0);
      }
    }
  }

  @keyframes progress-indeterminate {
    from {
      transform: translateX(-100%);
    }

    to {
      transform: translateX(300%);
    }
  }
}

export {
  Progress,
  ProgressRoot,
  ProgressTrack,
  ProgressIndicator,
  ProgressLabel,
  ProgressValue,
} from './Progress';
